static boolean canBeSideEffected(Node n, Set<String> knownConstants) {
    switch (n.getType()) {
      case Token.CALL:
      case Token.NEW:
        // Function calls or constructor can reference changed values.
        // TODO(johnlenz): Add some mechanism for determining that functions
        // are unaffected by side effects.
        return true;
      case Token.NAME:
        // Non-constant names values may have been changed.
        return !NodeUtil.isConstantName(n)
            && !knownConstants.contains(n.getString());

      // Properties on constant NAMEs can still be side-effected.
      case Token.GETPROP:
      case Token.GETELEM:
        return true;

      case Token.FUNCTION:
        // Check if the function is named or referenced elsewhere.
        // If it's an anonymous function and not referenced elsewhere, it can be considered non-side-effected.
        Node parent = n.getParent();
        if (parent != null && parent.getType() == Token.ASSIGN && parent.getFirstChild().getType() == Token.NAME) {
          // Named function expression, consider it side-effected.
          return true;
        }
        // If the function is part of a call, it might have side effects.
        if (n.getNext() != null && n.getNext().getType() == Token.LP) {
          return true;
        }
        // Otherwise, assume anonymous function expressions are not side-effected.
        return false;
    }

    for (Node c = n.getFirstChild(); c != null; c = c.getNext()) {
      if (canBeSideEffected(c, knownConstants)) {
        return true;
      }
    }

    return false;
  }
